<?php require_once '../../../includes/config.php'; require_once '../../../includes/db.php'; require_once '../../../includes/auth.php'; require_once '../../../includes/helpers.php'; require_role(['admin']); $pdo = get_pdo(); $id = isset($_GET['id']) ? (int)$_GET['id'] : 0; if (!$id) { flash('error', 'Semester tidak ditemukan'); redirect(APP_URL . '/admin/semester/index.php'); exit; } $stmt = $pdo->prepare("SELECT * FROM semester WHERE id_semester = ?"); $stmt->execute([$id]); $semester = $stmt->fetch(); if (!$semester) { flash('error', 'Semester tidak ditemukan'); redirect(APP_URL . '/admin/semester/index.php'); exit; } if ($_SERVER['REQUEST_METHOD'] === 'POST') { if (empty($_POST['_csrf']) || !csrf_verify($_POST['_csrf'])) { flash('error', 'CSRF token tidak valid'); } else { try { $stmt = $pdo->prepare("DELETE FROM semester WHERE id_semester = ?"); $stmt->execute([$id]); flash('success', 'Semester berhasil dihapus'); redirect(APP_URL . '/admin/semester/index.php'); exit; } catch (Exception $e) { flash('error', 'Error: ' . $e->getMessage()); } } } ?> <!DOCTYPE html> <html lang="id"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title>Hapus Semester - SIAKAD Gallery</title> <link rel="stylesheet" href="<?= APP_URL ?>/assets/css/style.css"> <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.10.0/font/bootstrap-icons.css"> <style> .delete-container { background: white; border-radius: 16px; padding: 40px; box-shadow: 0 2px 10px rgba(11, 30, 79, 0.06); max-width: 500px; text-align: center; } .delete-icon { font-size: 64px; color: #E04F5F; margin-bottom: 20px; display: block; } .delete-title { font-size: 24px; font-weight: 700; color: #0B1E4F; margin-bottom: 12px; } .delete-message { color: #6B7489; margin-bottom: 24px; } .delete-details { background: #FFEBEE; border: 1px solid #EF9A9A; border-radius: 8px; padding: 16px; margin-bottom: 24px; text-align: left; } .delete-actions { display: flex; gap: 12px; justify-content: center; } .btn-danger { padding: 10px 24px; background: #E04F5F; color: white; border: none; border-radius: 8px; font-weight: 600; cursor: pointer; } .btn-secondary { padding: 10px 24px; border-radius: 8px; border: 1px solid #E4E7EE; background: white; color: #2C3A59; text-decoration: none; cursor: pointer; font-weight: 500; } </style> </head> <body> <div class="app-container"> <?php include '../../../includes/header.php'; ?> <div class="main-content"> <?php include '../../../includes/sidebar.php'; ?> <div class="content-area"> <div class="delete-container"> <i class="bi bi-exclamation-triangle delete-icon"></i> <div class="delete-title">Hapus Semester?</div> <p class="delete-message">Anda akan menghapus semester dan semua data terkaitnya.</p> <div class="delete-details"> <div style="margin-bottom: 8px;"><strong>Tahun Ajaran:</strong> <?= h($semester['tahun_ajaran']) ?></div> <div><strong>Tingkatan:</strong> <?= ucfirst($semester['tingkatan_semester']) ?></div> </div> <form method="POST"> <input type="hidden" name="_csrf" value="<?= csrf_token() ?>"> <div class="delete-actions"> <button type="submit" class="btn-danger"><i class="bi bi-trash"></i> Ya, Hapus Permanen</button> <a href="<?= APP_URL ?>/admin/semester/index.php" class="btn-secondary"><i class="bi bi-x-circle"></i> Batalkan</a> </div> </form> </div> </div> </div> </div> <?php include '../../../includes/footer.php'; ?> </body> </html>
